const xml = $input.first().json.data;

const items = [];
const itemRegex = /<item>([\s\S]*?)<\/item>/g;
let match;

while ((match = itemRegex.exec(xml)) !== null) {
  const itemXml = match[1];

  const getTag = (tag) => {
    const r = new RegExp('<' + tag + '[^>]*>(?:<!\\[CDATA\\[)?([\\s\\S]*?)(?:\\]\\]>)?<\\/' + tag + '>');
    const m = itemXml.match(r);
    return m ? m[1].trim() : '';
  };

  const link = getTag('link');

  // Hash the FULL URL, not just the domain
  let hash = 0;
  for (let i = 0; i < link.length; i++) {
    const char = link.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  const urlHash = 'h_' + Math.abs(hash).toString(36);

  items.push({
    title: getTag('title'),
    link: link,
    description: getTag('description'),
    pubDate: getTag('pubDate'),
    urlHash: urlHash
  });
}

return [{ json: { articles: items.slice(0, 10) } }];

// Pull article data from Node 5, NOT from the SSH node (Node 6)
const article = $('Select Unprocessed Article').first().json;

const stripHtml = (html) => {
  if (!html) return '';
  return html
    .replace(/&nbsp;/g, ' ')
    .replace(/<[^>]*>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const title = article.title || '';
const link = article.link || '';
const description = article.description || '';
const cleanDesc = stripHtml(description);
const fullText = title + '. ' + cleanDesc;

if (fullText.length < 30) {
  throw new Error('Article content too short: "' + fullText + '"');
}

return [{
  json: {
    title: title,
    link: link,
    description: description,
    fullText: fullText
  }
}];

const ttsOutput = $('Generate Voice and Subtitles').first().json.stdout || '';
const scriptData = $('Parse Script Response').first().json;

// Extract timestamp from TTS output
const tsMatch = ttsOutput.match(/TIMESTAMP=(\d+)/);
if (!tsMatch) {
  throw new Error('Could not extract timestamp from TTS output: ' + ttsOutput);
}

const timestamp = tsMatch[1];

// Verify TTS completed
if (!ttsOutput.includes('TTS_DONE')) {
  throw new Error('TTS did not complete. Output: ' + ttsOutput);
}

// Verify no errors
if (ttsOutput.includes('ERROR:')) {
  const errorMatch = ttsOutput.match(/ERROR:.*/);
  throw new Error('TTS error: ' + (errorMatch ? errorMatch[0] : 'unknown'));
}

return [{
  json: {
    ...scriptData,
    timestamp: timestamp
  }
}];

const pexelsData = $input.first().json;
const timestamp = $('Extract Timestamp').first().json.timestamp;
const scriptData = $('Parse Script Response').first().json;

const videos = pexelsData.videos || [];

if (videos.length === 0) {
  throw new Error('No Pexels videos returned');
}

// Shuffle and pick 5
const shuffled = videos.sort(() => Math.random() - 0.5);
const selected = shuffled.slice(0, 5);

const downloadCmds = [];
const concatLines = [];

selected.forEach((video, i) => {
  // Find SD quality file closest to 1080x1920
  const files = video.video_files || [];
  const sdFile = files.find(f => f.width >= 338 && f.width <= 720 && f.height >= 640) 
    || files.find(f => f.quality === 'sd') 
    || files[0];

  if (sdFile && sdFile.link) {
    downloadCmds.push(
      'wget -q --timeout=15 --tries=2 "' + sdFile.link + '" -O /tmp/clip' + i + '_' + timestamp + '.mp4'
    );
    concatLines.push("file '/tmp/clip" + i + "_" + timestamp + ".mp4'");
  }
});

if (downloadCmds.length < 2) {
  throw new Error('Not enough video files found. Only got ' + downloadCmds.length);
}

return [{
  json: {
    ...scriptData,
    downloadCmds: downloadCmds.join('\n'),
    concatList: concatLines.join('\n'),
    clipCount: downloadCmds.length,
    timestamp: timestamp
  }
}];

const videoOutput = $('Read Video as Base64').first().json.stdout || '';
const thumbOutput = $('Read Thumbnail as Base64').first().json.stdout || '';

// Remove DEBUG lines, keep only base64
const videoB64 = videoOutput.split('\n').filter(l => !l.startsWith('DEBUG_TS=') && !l.startsWith('FATAL') && l.trim().length > 100).join('').trim();
const thumbB64 = thumbOutput.split('\n').filter(l => !l.startsWith('DEBUG_TS=') && !l.startsWith('FATAL') && l.trim().length > 100).join('').trim();

if (!videoB64 || videoB64.length < 5000) {
  throw new Error('Video base64 missing or too small. Length: ' + videoB64.length + '. Raw start: ' + videoOutput.substring(0, 200));
}

if (!thumbB64 || thumbB64.length < 500) {
  throw new Error('Thumbnail base64 missing or too small. Length: ' + thumbB64.length + '. Raw start: ' + thumbOutput.substring(0, 200));
}

let title = 'Cybersecurity News';
let description = '';
let tags = ['shorts', 'technews', 'cybersecurity'];

try {
  const scriptData = $('Parse Script Response').first().json;
  title = scriptData.title || title;
  description = scriptData.script || '';
  const hashtags = scriptData.hashtags || '';
  tags = hashtags.split(',').map(t => t.trim()).concat(tags);
  description = description + '\n\n' + hashtags + '\n\n#Shorts #CyberSecurity #Hacking';
} catch (e) {}

return [{
  json: {
    title: title,
    description: description,
    tags: tags,
    categoryId: '28',
    privacyStatus: 'public'
  },
  binary: {
    video: {
      data: videoB64,
      mimeType: 'video/mp4',
      fileName: 'short.mp4'
    },
    thumbnail: {
      data: thumbB64,
      mimeType: 'image/jpeg',
      fileName: 'thumb.jpg'
    }
  }
}];

