const scriptData = $('Parse Script Response').first().json;
const downloadData = $input.first().json;

const moodMap = {
  dark: ['dark1.mp3', 'dark2.mp3', 'dark3.mp3'],
  tense: ['tense1.mp3', 'tense2.mp3', 'tense3.mp3'],
  dramatic: ['dramatic1.mp3', 'dramatic2.mp3'],
  mysterious: ['mysterious1.mp3'],
  cinematic: ['cinematic1.mp3'],
  energetic: ['energetic1.mp3', 'energetic2.mp3'],
  corporate: ['corporate1.mp3'],
  upbeat: ['upbeat1.mp3'],
  serious: ['dark1.mp3', 'dark2.mp3', 'tense1.mp3'],
  urgent: ['tense1.mp3', 'tense2.mp3', 'dramatic1.mp3'],
  suspenseful: ['mysterious1.mp3', 'tense1.mp3']
};

let selectedMood = (scriptData.music_mood || 'dark').toLowerCase().trim();

// If mood contains pipe separator, pick first one
if (selectedMood.includes('|')) {
  const moods = selectedMood.split('|').map(m => m.trim());
  selectedMood = moods[0];
}

const originalMood = selectedMood;

const titleLower = (scriptData.title || '').toLowerCase();
if (/hack|breach|attack|exploit/.test(titleLower)) selectedMood = 'tense';
else if (/warn|alert|danger|critical/.test(titleLower)) selectedMood = 'dramatic';
else if (/spy|secret|hidden|dark/.test(titleLower)) selectedMood = 'mysterious';
else if (/million|billion|steal|theft/.test(titleLower)) selectedMood = 'dramatic';
else if (/exposed|leaked|caught|banned/.test(titleLower)) selectedMood = 'tense';

const files = moodMap[selectedMood] || moodMap['dark'];
const pick = files[Math.floor(Math.random() * files.length)];
const musicFile = '/home/YOUR_USERNAME/bgmusic/' + pick;

return [{
  json: {
    ...scriptData,
    downloadCmds: downloadData.downloadCmds || '',
    concatList: downloadData.concatList || '',
    clipCount: downloadData.clipCount || 0,
    timestamp: downloadData.timestamp || scriptData.timestamp || '',
    musicFile: musicFile,
    musicMood: selectedMood,
    originalMood: originalMood
  }
}];

const item = $input.first();
const stdout = item.json.stdout || '';
const stderr = item.json.stderr || '';
const exitCode = item.json.exitCode;

console.log('stdout:', stdout);
console.log('stderr:', stderr);
console.log('exitCode:', exitCode);

// Check for explicit failure message
if (stdout.includes('VALIDATION_FAILED')) {
  const errorMsg = stdout.match(/VALIDATION_FAILED: (.+)/)?.[1] || 'Voice validation failed';
  throw new Error(errorMsg);
}

// Check exit code
if (exitCode !== 0 && exitCode !== null && exitCode !== undefined) {
  throw new Error(`SSH command failed with exit code ${exitCode}: ${stderr || stdout}`);
}

// Check VALIDATION_PASSED exists
if (!stdout.includes('VALIDATION_PASSED')) {
  throw new Error(`Unexpected validation output: ${stdout.slice(0, 200)}`);
}

return [{ json: item.json }];

if (!$binary || !$binary.video) {
  throw new Error("No video file");
}

if ($binary.video.data.length < 1000000) {
  throw new Error("Video too small");
}

return items;

const articles = $('Parse Latest Article').first().json.articles;
const sshOutput = $('Check Processed URLs').first().json.stdout || '';
const processedHashes = sshOutput.split('\n').map(h => h.trim()).filter(h => h.length > 0);

// Check for override topic
let overrideTopic = '';
try {
  const overrideOutput = $('Check Override Topic').first().json.stdout || '';
  overrideTopic = overrideOutput.trim();
} catch (e) {}

let selectedArticle = null;

// If override topic exists, find matching article
if (overrideTopic && overrideTopic.length > 3 && overrideTopic !== 'OVERRIDE_CLEARED') {
  const keywords = overrideTopic.toLowerCase().split(/\s+/);

  for (const article of articles) {
    const title = (article.title || '').toLowerCase();
    const desc = (article.description || '').toLowerCase();

    // Check if any keyword matches
    const matchCount = keywords.filter(kw => kw.length > 3 && (title.includes(kw) || desc.includes(kw))).length;

    if (matchCount >= 2 || title.includes(overrideTopic.toLowerCase())) {
      selectedArticle = article;
      selectedArticle.overrideUsed = true;
      break;
    }
  }

  if (!selectedArticle) {
    // Try partial match with first 3 significant words
    const sigWords = keywords.filter(w => w.length > 4).slice(0, 3);
    for (const article of articles) {
      const title = (article.title || '').toLowerCase();
      const matches = sigWords.filter(w => title.includes(w)).length;
      if (matches >= 2) {
        selectedArticle = article;
        selectedArticle.overrideUsed = true;
        break;
      }
    }
  }
}

// If no override match, pick first unprocessed
if (!selectedArticle) {
  for (const article of articles) {
    if (!processedHashes.includes(article.urlHash)) {
      selectedArticle = article;
      break;
    }
  }
}

// If all processed, use oldest
if (!selectedArticle) {
  selectedArticle = { ...articles[articles.length - 1], reused: true };
}

return [{ json: selectedArticle }];

const item = $input.first().json;

// Build fullText from title + description (strip HTML)
const stripHtml = (html) => {
  if (!html) return '';
  return html
    .replace(/&nbsp;/g, ' ')
    .replace(/<[^>]*>/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const title = item.title || '';
const link = item.link || '';
const description = item.description || '';
const cleanDesc = stripHtml(description);
const fullText = title + '. ' + cleanDesc;

return [{
  json: {
    title: title,
    link: link,
    description: description,
    fullText: fullText
  }
}];

const articleData = $('Clean Article Text').first().json;
const fullText = articleData.fullText || '';
const articleTitle = articleData.title || '';
const articleLink = articleData.link || '';

if (!fullText || fullText === 'undefined' || fullText.length < 60) {
  throw new Error('ABORT: Article content is empty. fullText=' + fullText);
}

const duration = $json.duration || 90;
const minWords = Math.floor(duration * 2.0);
const maxWords = Math.floor(duration * 2.4);

const rules = [
  'Script MUST match a narration length of ' + duration + ' seconds',
  'Target word count: ' + minWords + '-' + maxWords + ' words',
  'Write in a dramatic, engaging, news-anchor style',
  'Start with a strong hook in the first sentence',
  'DO NOT use the word Welcome or Hey guys',
  'DO NOT repeat any word more than 3 times in the entire script',
  'DO NOT repeat any sentence or phrase anywhere in the script',
  'Every sentence must end with a period',
  'DO NOT use colons, semicolons, or bullet points',
  'DO NOT use quotation marks or apostrophes',
  'Avoid filler words like basically, actually, literally',
  'DO NOT start consecutive sentences with the same word',
  'Reference specific technical details, CVEs, companies, or threat actors',
  'End with a strong cybersecurity safety takeaway or warning',
  'The VERY LAST sentence must be exactly: Subscribe to our channel for the latest cybersecurity updates and news and follow for more.',
  'Do NOT write any variation of subscribe more than once in the entire script'
].map(r => '- ' + r).join('\n');

const prompt =
  'You are a YouTube Shorts script writer for a cybersecurity news channel.\n\n' +
  'ARTICLE TITLE: ' + articleTitle + '\n' +
  'SOURCE: ' + articleLink + '\n\n' +
  'ARTICLE CONTENT:\n' + fullText + '\n\n' +
  'CRITICAL INSTRUCTION:\n' +
  'You MUST generate a script that matches exactly the requested duration. Timing matters more than word count.\n\n' +
  rules + '\n\n' +
  'Return ONLY valid JSON in this exact format (no markdown, no backticks):\n' +
  '{\n' +
  '  "title": "Short catchy title under 60 chars",\n' +
  '  "script": "The full narration script here",\n' +
  '  "thumbnail_text": "2-4 WORDS IN ALL CAPS",\n' +
  '  "hashtags": "tag1, tag2, tag3",\n' +
  '  "search_keywords": "keyword1, keyword2, keyword3",\n' +
  '  "music_mood": "dark|tense|dramatic|mysterious|cinematic|energetic"\n' +
  '}';

return [{
  json: {
    articleTitle,
    articleLink,
    duration,
    requestBody: {
      model: 'llama-3.1-8b-instant',
      temperature: 0.75,
      max_tokens: 2200,
      messages: [
        {
          role: 'system',
          content: 'You are a professional YouTube Shorts script writer specializing in cybersecurity news. You MUST strictly follow duration-based pacing rules. Output ONLY valid JSON. Never repeat any sentence in the script.'
        },
        {
          role: 'user',
          content: prompt
        }
      ]
    }
  }
}];

const articleTitle = $('Build Script Prompt').first().json.articleTitle;
const articleLink = $('Build Script Prompt').first().json.articleLink;

const data = $input.first().json;

if (!data.choices || !data.choices[0]) {
  throw new Error('API returned no choices: ' + JSON.stringify(data).substring(0, 500));
}

let rawText = data.choices[0].message.content.trim();

// Clean up common formatting issues
rawText = rawText.replace(/```json\s*/g, '');
rawText = rawText.replace(/```\s*/g, '');
rawText = rawText.trim();

// Try to extract JSON object if there is extra text around it
const jsonStart = rawText.indexOf('{');
const jsonEnd = rawText.lastIndexOf('}');

if (jsonStart === -1 || jsonEnd === -1) {
  throw new Error('No JSON object found in response: ' + rawText.substring(0, 500));
}

rawText = rawText.substring(jsonStart, jsonEnd + 1);

// Fix common JSON issues from small models
rawText = rawText.replace(/[\r\n]+/g, ' ');
rawText = rawText.replace(/,\s*}/g, '}');
rawText = rawText.replace(/,\s*,/g, ',');

// Fix unescaped quotes inside values
// Replace smart quotes with straight quotes first
rawText = rawText.replace(/[\u201C\u201D]/g, '\\"');
rawText = rawText.replace(/[\u2018\u2019]/g, "'");

let result;
try {
  result = JSON.parse(rawText);
} catch (e) {
  // Second attempt: try to fix broken quotes
  try {
    // Replace single quotes used as string delimiters with double quotes
    let fixed = rawText.replace(/'/g, '"');
    result = JSON.parse(fixed);
  } catch (e2) {
    // Third attempt: manually extract fields with regex
    try {
      result = {
        title: (rawText.match(/"title"\s*:\s*"([^"]*)"/) || [])[1] || articleTitle,
        script: (rawText.match(/"script"\s*:\s*"([\s\S]*?)"\s*,\s*"thumbnail/) || [])[1] || '',
        thumbnail_text: (rawText.match(/"thumbnail_text"\s*:\s*"([^"]*)"/) || [])[1] || 'BREAKING NEWS',
        hashtags: (rawText.match(/"hashtags"\s*:\s*"([^"]*)"/) || [])[1] || 'cybersecurity, hacking, infosec',
        search_keywords: (rawText.match(/"search_keywords"\s*:\s*"([^"]*)"/) || [])[1] || 'cybersecurity news, hacking',
        music_mood: (rawText.match(/"music_mood"\s*:\s*"([^"]*)"/) || [])[1] || 'dark'
      };

      if (!result.script || result.script.length < 50) {
        throw new Error('Regex extraction got empty script');
      }
    } catch (e3) {
      throw new Error('All JSON parse attempts failed. Raw response: ' + rawText.substring(0, 800));
    }
  }
}

const script = result.script || '';
const words = script.toLowerCase().split(/\s+/);
let retryReason = '';
const issues = [];

if (words.length < 240 || words.length > 280) {
  issues.push('Word count is ' + words.length);
}

const freq = {};
const skip = ['the','a','an','is','are','was','were','and','or','but','in','on','to','of','for','it','that','this','with','from','has','have','had','not','can','will','be','by','as','at','its','their','they','you','your'];
words.forEach(w => {
  const clean = w.replace(/[^a-z]/g, '');
  if (clean.length > 3 && !skip.includes(clean)) {
    freq[clean] = (freq[clean] || 0) + 1;
  }
});

const repeated = Object.entries(freq)
  .filter(([w, c]) => c > 4)
  .map(([w, c]) => '"' + w + '" x' + c);
if (repeated.length > 0) {
  issues.push(repeated.join(', '));
}

if (issues.length > 0) {
  retryReason = issues.join('; ');
}

const scriptSafe = (result.script || '')
  .replace(/'/g, '')
  .replace(/"/g, '')
  .replace(/`/g, '')
  .replace(/\$/g, '')
  .replace(/\\/g, '')
  .replace(/[^\x20-\x7E\n]/g, '');

const thumbnailSafe = (result.thumbnail_text || 'BREAKING NEWS')
  .toUpperCase()
  .replace(/'/g, '')
  .replace(/"/g, '');

const wordsFinal = scriptSafe.split(/\s+/).filter(w => w.length > 0);
const sentenceEndings = (scriptSafe.match(/\./g) || []).length;

return [{
  json: {
    title: result.title || articleTitle,
    script: result.script || '',
    thumbnail_text: result.thumbnail_text || 'BREAKING NEWS',
    hashtags: result.hashtags || 'cybersecurity, hacking, infosec',
    search_keywords: result.search_keywords || 'cybersecurity news, hacking, data breach',
    music_mood: result.music_mood || 'dark',
    scriptSafe: scriptSafe,
    thumbnailSafe: thumbnailSafe,
    wordCount: wordsFinal.length,
    sentenceEndings: sentenceEndings,
    retried: false,
    retryReason: retryReason,
    articleLink: articleLink
  }
}];

const article = $('Select Unprocessed Article').first().json;
return [{
  json: {
    urlHash: article.urlHash,
    title: article.title,
    link: article.link,
    description: article.description
  }
}];

return [
  {
    json: {
      hasBinary: !!$binary,
      keys: Object.keys($binary || {}),
      videoSize: $binary?.video?.data?.length || 0
    }
  }
];
